(() => {
const $=(s,e=document)=>e.querySelector(s),$$=(s,e=document)=>Array.from(e.querySelectorAll(s));
const esc=(v)=>String(v??'').replace(/[&<>"']/g,(ch)=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[ch]));
const clamp=(v,min,max)=>Math.max(min,Math.min(max,v));
const TOOL_SHARE={'/tools/ai-domain-analysis/':{key:'domain',result:'/tools/results/domain/'},'/tools/ai-notice-check/':{key:'notice',result:'/tools/results/notice/'},'/tools/rolling-calculator/':{key:'rolling',result:'/tools/results/rolling/'},'/tools/recurring-bonus/':{key:'bonus',result:'/tools/results/bonus/'},'/tools/ai-sports-odds-analysis/':{key:'sports',result:'/tools/results/sports/'}};
function toast(msg){let t=$('#contentUpgradeToast');if(!t){t=document.createElement('div');t.id='contentUpgradeToast';t.className='safety-toast';document.body.appendChild(t);}t.textContent=msg;t.classList.add('is-show');clearTimeout(toast._timer);toast._timer=setTimeout(()=>t.classList.remove('is-show'),1800);}
async function copyText(text,msg='복사했습니다.'){try{await navigator.clipboard.writeText(String(text||''));toast(msg);}catch(_){const ta=document.createElement('textarea');ta.value=String(text||'');ta.style.position='fixed';ta.style.opacity='0';document.body.appendChild(ta);ta.select();try{document.execCommand('copy');toast(msg);}catch(__){toast('복사가 제한되었습니다.');}ta.remove();}}
function normalizeDomain(value=''){let v=String(value||'').trim();if(!v)return'';try{const u=new URL(/^[a-z][a-z0-9+.-]*:/.test(v)?v:`https://${v}`);v=u.hostname||'';}catch(_){}return String(v).toLowerCase().replace(/^www\./,'').replace(/\.$/,'').split('/')[0].replace(/:\d+$/,'');}
function splitLines(v=''){return String(v||'').split(/\n+/).map((x)=>x.trim()).filter(Boolean);}
function extractDomains(text=''){return Array.from(new Set((String(text).match(/(?:https?:\/\/)?(?:www\.)?([a-z0-9-]+(?:\.[a-z0-9-]+)+)/gi)||[]).map((x)=>normalizeDomain(x)).filter(Boolean)));}
function extractCodes(text=''){return Array.from(new Set((String(text).match(/[A-Z0-9]{3,10}/g)||[]).filter((x)=>/[A-Z]/.test(x))));}
function won(n){return `${Math.round(Number(n||0)).toLocaleString()}원`;}
function pct(n){return `${Number(n||0).toFixed(1)}%`;}
function signedPct(n){const num=Number(n||0);return `${num>=0?'+':''}${num.toFixed(1)}%`;}
function section(title,desc,body){return `<section class="surface card"><div class="section-head"><div><h2>${esc(title)}</h2><p>${esc(desc||'')}</p></div></div>${body}</section>`;}
function metricGrid(items){return `<div class="summary-tile-grid">${items.map((i)=>`<article class="summary-tile"><span>${esc(i.label)}</span><strong>${esc(i.value)}</strong>${i.note?`<p>${esc(i.note)}</p>`:''}</article>`).join('')}</div>`;}
function points(items){return `<ul class="inline-checklist">${items.map((i)=>`<li>${esc(i)}</li>`).join('')}</ul>`;}
function queryFromObject(obj){const p=new URLSearchParams();Object.entries(obj).forEach(([k,v])=>{if(v===undefined||v===null||v==='')return;p.set(k,String(v));});return p.toString();}
function readParams(){const p=new URLSearchParams(location.search);const out={};for(const [k,v] of p.entries()) out[k]=v;return out;}
function fairNormalize(odds){const inv=odds.map((odd)=>1/odd);const sum=inv.reduce((a,b)=>a+b,0)||1;return inv.map((v)=>v/sum);}
function renderDomain(payload){const seed=String(payload.seed||'').trim(),candidates=String(payload.candidates||'').trim(),evidence=String(payload.evidence||'').trim();const lines=splitLines([seed,candidates,evidence].filter(Boolean).join('\n'));const domains=Array.from(new Set(lines.flatMap((line)=>{const d=normalizeDomain(line);return d?[d]:extractDomains(line);})));const official=domains[0]||normalizeDomain(seed)||'-';const codes=extractCodes(evidence);const relation=clamp(domains.length*12+codes.length*8+(/리뉴얼|변경|같은|공통|동일/i.test(evidence)?18:0),0,100);const table=`<div class="card"><table class="toolkit-table"><thead><tr><th>입력값</th><th>정규화</th><th>판정</th></tr></thead><tbody>${lines.map((line)=>{const d=normalizeDomain(line)||extractDomains(line)[0]||'';const verdict=!d?'확인 필요':(d===official||d.endsWith('.'+official)?'일치 후보':'추가 확인');return `<tr><td>${esc(line)}</td><td>${esc(d||'-')}</td><td>${esc(verdict)}</td></tr>`;}).join('')}</tbody></table></div>`;const timelineRows=splitLines(evidence||candidates||seed).map((line,idx)=>({date:(line.match(/20\d{2}[./-]\d{1,2}(?:[./-]\d{1,2})?|20\d{2}년\s*\d{1,2}월?/)||[`기록 ${String(idx+1).padStart(2,'0')}`])[0],line,kind:/리뉴얼|변경|이전|신규|공지/i.test(line)?'변경':'참고',domains:extractDomains(line)}));const timeline=`<div class="timeline-list">${timelineRows.length?timelineRows.map((r)=>`<article class="timeline-entry"><span class="mini-badge">${esc(r.date)}</span><strong>${esc(r.kind)}</strong><p>${esc(r.line)}</p>${r.domains.length?`<small>${esc(r.domains.join(' · '))}</small>`:''}</article>`).join(''):'<div class="toolkit-note">변경 이력으로 읽을 텍스트가 아직 없습니다.</div>'}</div>`;return {title:seed||official||'사이트·도메인 분석 결과',html:section('핵심 요약','주소·변경 흐름·계열 신호를 먼저 정리했습니다.',metricGrid([{label:'기준 후보',value:official},{label:'주소 후보 수',value:`${domains.length}개`,note:domains.slice(0,2).join(' · ')||'입력 기준'},{label:'코드 신호',value:`${codes.length}개`,note:codes.slice(0,2).join(' · ')||'없음'},{label:'계열 신호 점수',value:`${relation}점`,note:relation>=70?'재확인 필요':'참고 수준'}]))+section('주소 정합성','같은 기준으로 정규화한 뒤 판정을 붙였습니다.',table)+section('변경 이력','리뉴얼·주소 변경 흐름을 순서대로 봅니다.',timeline)+section('실전 메모','지금 바로 확인할 포인트만 남겼습니다.',points([official!=='-'?`기준 후보 주소는 ${official} 입니다.`:'기준 주소는 추가 확인이 필요합니다.',domains.length>1?'후보 주소가 여러 개라 공지와 채널을 함께 대조해야 합니다.':'주소 후보 수가 많지 않습니다.',/리뉴얼|변경/i.test(evidence)?'리뉴얼·변경 표현이 있어 시간순 재확인이 필요합니다.':'큰 변경 표현은 많지 않습니다.']))};}
function renderNotice(payload){const official=String(payload.official||'').trim(),channel=String(payload.channel||'').trim();const offDomains=extractDomains(official),chDomains=extractDomains(channel),offCodes=extractCodes(official),chCodes=extractCodes(channel);const warnings=[];if(offDomains.join('|')!==chDomains.join('|'))warnings.push('주소 표기가 다르게 보입니다.');if(offCodes.join('|')!==chCodes.join('|'))warnings.push('가입코드 표기가 다르게 보입니다.');if(/긴급|즉시|오늘만|마감임박/.test(official+channel))warnings.push('긴급·과장 표현이 섞여 있습니다.');if(!warnings.length)warnings.push('큰 불일치는 적습니다.');const table=`<div class="card"><table class="toolkit-table"><thead><tr><th>항목</th><th>사이트 공지</th><th>채널·후기</th></tr></thead><tbody><tr><td><strong>주소</strong></td><td>${esc(offDomains.join(', ')||'-')}</td><td>${esc(chDomains.join(', ')||'-')}</td></tr><tr><td><strong>가입코드</strong></td><td>${esc(offCodes.join(', ')||'-')}</td><td>${esc(chCodes.join(', ')||'-')}</td></tr></tbody></table></div>`;return {title:'공지·후기 비교 결과',html:section('핵심 요약','주소, 코드, 과장 표현을 먼저 비교했습니다.',metricGrid([{label:'사이트 공지',value:`${official.length||0}자`,note:offDomains[0]||'주소 없음'},{label:'채널·후기',value:`${channel.length||0}자`,note:chDomains[0]||'주소 없음'},{label:'주소 차이',value:offDomains.join('|')===chDomains.join('|')?'적음':'있음',note:'최신 주소 우선'},{label:'주의 포인트',value:`${warnings.length}개`,note:warnings[0]}]))+section('비교 표','공식 공지와 채널 문구를 같은 기준으로 봅니다.',table)+section('실전 메모','공지보다 먼저 확인할 포인트입니다.',points(warnings.concat(['후기 쪽에 실사용 정보가 있는지 같이 확인하세요.','주소가 다르면 공식 주소 확인 도구로 한 번 더 점검하세요.'])))};}
function renderRolling(payload){const deposit=Number(payload.deposit||0),bonus=Number(payload.bonus||0),multiplier=Number(payload.multiplier||0),total=deposit+bonus,required=total*multiplier,burden=total?required/total:0;return {title:'롤링 계산 결과',html:section('핵심 요약','필요 롤링과 체감 부담만 먼저 정리했습니다.',metricGrid([{label:'충전금',value:won(deposit)},{label:'보너스',value:won(bonus)},{label:'총 사용금',value:won(total)},{label:'필요 롤링',value:won(required),note:`${multiplier||0}배`}]))+section('실전 메모','조건 해석 전에 먼저 볼 숫자입니다.',points([`총 사용금은 ${won(total)} 입니다.`,`필요 롤링은 ${won(required)} 입니다.`,burden>=10?'롤링 부담이 커 보수적으로 보는 편이 좋습니다.':'부담이 아주 높지는 않습니다.']))};}
function renderBonus(payload){const deposit=Number(payload.deposit||0),percent=Number(payload.percent||0),cap=Number(payload.cap||0),rolling=Number(payload.rolling||0),max=Number(payload.max||0);const bonus=Math.min(deposit*(percent/100),cap||Infinity),total=deposit+bonus,need=total*rolling,effective=max?Math.min(total,max):total,diff=need>total*15?'높음':need>total*8?'보통':'낮음';return {title:'보너스 비교 결과',html:section('핵심 요약','보너스보다 실수령과 필요 롤링을 먼저 정리했습니다.',metricGrid([{label:'보너스',value:won(bonus),note:`${percent||0}%`},{label:'총 사용금',value:won(total),note:'입금 + 보너스'},{label:'필요 롤링',value:won(need),note:`${rolling||0}배`},{label:'실수령 기준',value:won(effective),note:`부담 ${diff}`}]))+section('실전 메모','체감 한도와 롤링을 같이 보세요.',points([max?`최대 출금 제한을 적용하면 체감 수령은 ${won(effective)} 입니다.`:'최대 출금 제한이 없으면 총 사용금 기준으로 봅니다.',diff==='높음'?'퍼센트가 높아도 실제 부담이 큰 구조입니다.':'숫자만 보면 과도한 부담은 아닙니다.','규정 문구에 제한·몰수 표현이 있으면 더 보수적으로 봐야 합니다.']))};}
function renderSports(payload){const mode=payload.mode||'sports';if(mode==='condition'){const deposit=Number(payload.capital||0),percent=Number(payload.percent||0),rolling=Number(payload.rolling||0),max=Number(payload.maxWithdraw||0),bonus=deposit*(percent/100),total=deposit+bonus,need=total*rolling,effective=max?Math.min(total,max):total,burden=clamp((need/Math.max(total,1))*6+(/양방|제한|몰수|회수/.test(payload.rules||'')?12:0),0,100);return {title:'조건 해석 결과',html:section('핵심 요약','조건 해석 모드 기준으로 체감만 먼저 봅니다.',metricGrid([{label:'보너스',value:won(bonus)},{label:'필요 롤링',value:won(need),note:`${rolling||0}배`},{label:'실수령 기준',value:won(effective)},{label:'조건 부담',value:burden>=70?'높음':burden>=45?'보통':'낮음',note:`${burden.toFixed(0)}점`}]))+section('실전 메모','퍼센트보다 롤링과 최대 출금을 먼저 보세요.',points(['규정 문구의 제한·몰수 표현도 같이 확인하세요.','최대 출금은 체감 수익을 직접 깎는 값입니다.','비슷한 조건은 보너스 결과 페이지를 여러 개 열어 비교하는 편이 좋습니다.']))};}
if(mode==='casino'||mode==='mini'){const capital=Number(payload.capital||0),unit=Number(payload.unit||0),rounds=Number(payload.rounds||0),a=Number(payload.oddA||0),b=Number(payload.oddB||0),vol=mode==='casino'?(b>2?'높음':'보통'):(rounds>10?'높음':'보통');return {title:mode==='casino'?'카지노 세션 결과':'미니게임 운영 결과',html:section('핵심 요약','세션 기준 운영 지표만 먼저 봅니다.',metricGrid([{label:'현재 자본',value:won(capital)},{label:'1회 금액',value:won(unit)},{label:'회차',value:`${rounds||0}회`,note:mode==='casino'?`RTP ${a||0}`:'세션 기준'},{label:'변동성',value:vol,note:mode==='casino'?'세션 흔들림':'회차 운영'}]))+section('실전 메모','기준금과 회차를 같이 보면 흔들림을 읽기 쉽습니다.',points(['기준금이 총 자본 대비 크면 변동성이 더 커집니다.','회차가 늘수록 손절 기준을 먼저 정하는 편이 좋습니다.','미니게임은 결과보다 운영 리듬을 먼저 보는 편이 낫습니다.']))};}
const market=payload.market||'1x2',odds=[Number(payload.oddA||0),Number(payload.oddB||0),Number(payload.oddC||0)].filter((v)=>v>1.01),labels=market==='1x2'?['홈','무','원정']:market==='moneyline'?['홈','원정']:market==='ou'?['오버','언더']:['홈','원정'];const probs=fairNormalize(odds),outcomes=odds.map((odd,idx)=>{const prob=probs[idx]||0,fairOdd=prob?1/prob:0,ev=prob*odd-1;return{label:labels[idx]||`선택 ${idx+1}`,prob,fairOdd,ev};}),bestProb=outcomes.slice().sort((a,b)=>b.prob-a.prob)[0]||{label:'-',prob:0,ev:0},bestEv=outcomes.slice().sort((a,b)=>b.ev-a.ev)[0]||{label:'-',ev:0},capital=Number(payload.capital||0),stake=capital?capital*0.03:0;return {title:'스포츠·게임 분석 결과',html:section('핵심 요약','공정확률과 기대값을 먼저 계산했습니다.',metricGrid([{label:'공정확률 우세',value:`${bestProb.label} ${pct(bestProb.prob*100)}`,note:`시장 ${market}`},{label:'기대값 우세',value:`${bestEv.label} ${signedPct(bestEv.ev*100)}`,note:'입력 배당 기준'},{label:'추정 공정배당',value:bestProb.fairOdd?bestProb.fairOdd.toFixed(2):'-',note:bestProb.label},{label:'권장 기준금',value:stake?won(stake):'선택 입력',note:'자본 3% 기준'}]))+section('시장별 수치','입력한 선택지별 수치를 같이 봅니다.',`<div class="card"><table class="toolkit-table"><thead><tr><th>선택</th><th>공정확률</th><th>공정배당</th><th>EV</th></tr></thead><tbody>${outcomes.map((o)=>`<tr><td><strong>${esc(o.label)}</strong></td><td>${esc(pct(o.prob*100))}</td><td>${esc(o.fairOdd?o.fairOdd.toFixed(2):'-')}</td><td>${esc(signedPct(o.ev*100))}</td></tr>`).join('')}</tbody></table></div>`)+section('실전 메모','숫자를 운영 판단으로 바꿀 때 참고할 포인트입니다.',points([`${bestProb.label} 쪽 공정확률이 조금 더 앞섭니다.`,`${bestEv.label} 기준 기대값이 상대적으로 좋습니다.`,'변동성이 큰 시장일수록 기준금은 더 보수적으로 잡는 편이 좋습니다.']))};}
function renderByKey(key,payload){if(key==='domain')return renderDomain(payload);if(key==='notice')return renderNotice(payload);if(key==='rolling')return renderRolling(payload);if(key==='bonus')return renderBonus(payload);return renderSports(payload);}
function injectToolTemplate(){if(document.body?.dataset?.communityPage!=='tool-detail')return;const config={'/tools/ai-domain-analysis/':{heading:'입력 예시와 읽는 순서',sub:'기준값, 근거 텍스트, 결과 해석 순서를 한 번에 맞춥니다.',items:[{label:'입력 예시',value:'기준 주소 + 후보 주소 + 공지문',note:'세 줄만 넣어도 됩니다.'},{label:'먼저 볼 것',value:'기준 후보 주소',note:'주소 정합성부터 확인'},{label:'다음 볼 것',value:'변경 이력',note:'리뉴얼·변경 표현'},{label:'마지막 확인',value:'공식 주소',note:'보증업체/채널 대조'}]},'/tools/ai-notice-check/':{heading:'입력 예시와 읽는 순서',sub:'사이트 공지와 채널 문구를 붙여 넣은 뒤 주소·코드부터 읽습니다.',items:[{label:'입력 예시',value:'공지 2개 붙여넣기',note:'원문 그대로'},{label:'먼저 볼 것',value:'주소 차이',note:'공식 주소 우선'},{label:'다음 볼 것',value:'가입코드',note:'표기 일치 확인'},{label:'마지막 확인',value:'과장 문구',note:'긴급·즉시 표현'}]},'/tools/rolling-calculator/':{heading:'입력 예시와 읽는 순서',sub:'충전금, 보너스, 배수만 넣고 총 사용금과 필요 롤링을 같이 봅니다.',items:[{label:'입력 예시',value:'300000 / 60000 / 5',note:'충전금 / 보너스 / 배수'},{label:'먼저 볼 것',value:'필요 롤링',note:'가장 큰 부담 수치'},{label:'다음 볼 것',value:'총 사용금',note:'입금 + 보너스'},{label:'마지막 확인',value:'최대 출금',note:'보너스 비교로 이동'}]},'/tools/recurring-bonus/':{heading:'입력 예시와 읽는 순서',sub:'퍼센트보다 롤링과 최대 출금을 같이 읽는 흐름으로 맞췄습니다.',items:[{label:'입력 예시',value:'300000 / 20 / 60000',note:'충전금 / % / 최대지급'},{label:'먼저 볼 것',value:'실수령 기준',note:'최대 출금 반영'},{label:'다음 볼 것',value:'필요 롤링',note:'조건 부담 확인'},{label:'마지막 확인',value:'규정 문구',note:'제한·몰수 표현'}]},'/tools/ai-sports-odds-analysis/':{heading:'입력 예시와 읽는 순서',sub:'모드에 따라 공정확률, 조건 부담, 세션 운영 판단을 분리해 봅니다.',items:[{label:'입력 예시',value:'시장 선택 + 숫자 입력',note:'모드별로 값 해석'},{label:'먼저 볼 것',value:'공정확률/실수령',note:'모드별 핵심 수치'},{label:'다음 볼 것',value:'기대값/부담도',note:'운영 리스크 판단'},{label:'마지막 확인',value:'추천 비중',note:'기준금 보수 적용'}]}}[location.pathname];if(!config)return;const anchor=$('.tool-detail-card, .tool-form-card');if(!anchor||anchor.previousElementSibling?.classList?.contains('tool-template-summary'))return;const node=document.createElement('section');node.className='surface card tool-template-summary';node.innerHTML=`<div class="section-head"><div><h2>${esc(config.heading)}</h2><p>${esc(config.sub)}</p></div></div>${metricGrid(config.items)}`;anchor.insertAdjacentElement('beforebegin',node);}
async function injectBlogTemplate(){if(!location.pathname.startsWith('/blog/')||location.pathname==='/blog/')return;const article=$('.article-single');if(!article||article.previousElementSibling?.classList?.contains('article-template-summary'))return;try{const res=await fetch('/assets/data/posts.index.v1.20260318.json',{cache:'no-store'});const data=await res.json();const slug=location.pathname.replace(/^\/blog\//,'').replace(/\/$/,'');const current=(data.posts||[]).find((item)=>String(item.slug||'')===slug);if(!current)return;const tiles=(current.sections||[]).slice(0,4).map((item)=>({label:item[0],value:item[1]}));const node=document.createElement('section');node.className='surface card article-template-summary';node.innerHTML=`<div class="section-head"><div><h2>핵심 요약</h2><p>${esc(current.excerpt||current.description||'현재 글에서 바로 써먹을 포인트만 먼저 정리했습니다.')}</p></div></div>${metricGrid(tiles.length?tiles:[{label:'핵심',value:current.excerpt||''}])}`;article.insertAdjacentElement('beforebegin',node);}catch(_){}}
function buildSharePayload(path){if(path==='/tools/ai-domain-analysis/')return{seed:$('#aiDomainSeed')?.value||'',candidates:$('#aiDomainCandidates')?.value||'',evidence:$('#aiDomainEvidence')?.value||''};if(path==='/tools/ai-notice-check/')return{official:$('#aiNoticeOfficial')?.value||'',channel:$('#aiNoticeChannel')?.value||''};if(path==='/tools/rolling-calculator/')return{deposit:$('#rollDeposit')?.value||'',bonus:$('#rollBonus')?.value||'',multiplier:$('#rollMultiplier')?.value||''};if(path==='/tools/recurring-bonus/')return{deposit:$('#repeatDeposit')?.value||'',percent:$('#repeatPercent')?.value||'',cap:$('#repeatCap')?.value||'',rolling:$('#repeatRolling')?.value||'',max:$('#repeatMax')?.value||''};return{mode:$('#centerMode')?.value||'sports',market:$('#centerMarket')?.value||'1x2',line:$('#centerLine')?.value||'',oddA:$('#centerOddA')?.value||'',oddB:$('#centerOddB')?.value||'',oddC:$('#centerOddC')?.value||'',capital:$('#centerCapital')?.value||'',unit:$('#centerUnit')?.value||'',rounds:$('#centerRounds')?.value||'',percent:$('#centerPercent')?.value||'',rolling:$('#centerRolling')?.value||'',maxWithdraw:$('#centerMaxWithdraw')?.value||'',risk:$('#centerRisk')?.value||'neutral',rules:$('#centerRules')?.value||''};}
function fillToolFromParams(path){const p=new URLSearchParams(location.search);const set=(id,key=id)=>{const el=document.getElementById(id),value=p.get(key);if(el&&value!==null)el.value=value;};if(path==='/tools/ai-domain-analysis/')[['aiDomainSeed','seed'],['aiDomainCandidates','candidates'],['aiDomainEvidence','evidence']].forEach(([id,key])=>set(id,key));if(path==='/tools/ai-notice-check/')[['aiNoticeOfficial','official'],['aiNoticeChannel','channel']].forEach(([id,key])=>set(id,key));if(path==='/tools/rolling-calculator/')[['rollDeposit','deposit'],['rollBonus','bonus'],['rollMultiplier','multiplier']].forEach(([id,key])=>set(id,key));if(path==='/tools/recurring-bonus/')[['repeatDeposit','deposit'],['repeatPercent','percent'],['repeatCap','cap'],['repeatRolling','rolling'],['repeatMax','max']].forEach(([id,key])=>set(id,key));if(path==='/tools/ai-sports-odds-analysis/'){const map={mode:'centerMode',market:'centerMarket',line:'centerLine',oddA:'centerOddA',oddB:'centerOddB',oddC:'centerOddC',capital:'centerCapital',unit:'centerUnit',rounds:'centerRounds',percent:'centerPercent',rolling:'centerRolling',maxWithdraw:'centerMaxWithdraw',risk:'centerRisk',rules:'centerRules'};Object.entries(map).forEach(([key,id])=>set(id,key));}}
function renderRollingOnTool(){const form=$('#rollingcalculatorForm'),result=$('#rollingCalcResult');if(!form||!result)return;form.addEventListener('submit',(e)=>{e.preventDefault();const rendered=renderRolling(buildSharePayload('/tools/rolling-calculator/'));result.className='toolkit-result-stack';result.innerHTML=rendered.html;revealSharePanel();});}
function renderBonusOnTool(){const form=$('#recurringbonusForm'),result=$('#recurringBonusResult');if(!form||!result)return;form.addEventListener('submit',(e)=>{e.preventDefault();const rendered=renderBonus(buildSharePayload('/tools/recurring-bonus/'));result.className='toolkit-result-stack';result.innerHTML=rendered.html;revealSharePanel();});}
function revealSharePanel(){const panel=$('#toolSharePanel');if(panel)panel.hidden=false;}
function initToolShare(){const config=TOOL_SHARE[location.pathname];if(!config)return;fillToolFromParams(location.pathname);if(location.pathname==='/tools/rolling-calculator/')renderRollingOnTool();if(location.pathname==='/tools/recurring-bonus/')renderBonusOnTool();const anchor=$('.tool-detail-card, .tool-form-card');if(!anchor||$('#toolSharePanel'))return;const panel=document.createElement('section');panel.id='toolSharePanel';panel.className='tool-share-panel';panel.hidden=true;panel.innerHTML='<strong>결과 페이지로 저장</strong><small>현재 입력값을 공유 가능한 결과 URL로 열거나 복사할 수 있습니다.</small><a class="safety-link-btn" href="#" data-share-open>결과 페이지 열기</a><button class="safety-copy-btn ghost" type="button" data-share-copy>공유 URL 복사</button>';anchor.insertAdjacentElement('afterend',panel);const createUrl=()=>`${config.result}?${queryFromObject(buildSharePayload(location.pathname))}`;panel.addEventListener('click',async(e)=>{const open=e.target.closest('[data-share-open]'),copy=e.target.closest('[data-share-copy]');if(open){e.preventDefault();window.location.href=createUrl();}if(copy){e.preventDefault();await copyText(location.origin+createUrl(),'공유 URL을 복사했습니다.');}});const form=$('form',anchor);form?.addEventListener('submit',()=>{setTimeout(revealSharePanel,20);});form?.addEventListener('input',()=>{if(Object.values(buildSharePayload(location.pathname)).some((v)=>String(v).trim()))panel.hidden=false;});if(new URLSearchParams(location.search).toString()){setTimeout(()=>{form?.dispatchEvent(new Event('submit',{bubbles:true,cancelable:true}));},140);panel.hidden=false;}}
function renderResultPage(){if(!location.pathname.startsWith('/tools/results/'))return;const mount=$('#resultPageMount');if(!mount)return;const key=location.pathname.replace(/^\/tools\/results\//,'').replace(/\/$/,'');if(!key||key==='results')return;const rendered=renderByKey(key,readParams());mount.innerHTML=rendered.html;const title=$('#resultPageHeaderTitle');if(title)title.textContent=rendered.title;$('#resultPageCopy')?.addEventListener('click',async(e)=>{e.preventDefault();await copyText(location.href,'현재 결과 URL을 복사했습니다.');});const pathByKey=Object.entries(TOOL_SHARE).find(([,v])=>v.key===key)?.[0];const edit=$('#resultPageEdit');if(edit&&pathByKey)edit.href=`${pathByKey}?${location.search.replace(/^\?/,'')}`;}
function init(){injectToolTemplate();injectBlogTemplate();initToolShare();renderResultPage();}
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',init);else init();})();